// Unit 16 — 뭐라고 했어요?
// Indirect Speech

export default {n:16,lang:"ko",srcLang:"en",track:"v2",title:"뭐라고 했어요?",sub:"Indirect Speech",icon:"💬",level:"B1.2",color:"#7B5EE8",lessons:[
  {id:"kou16l1",title:"인터넷 어휘",icon:"📱",xp:22,board:true,steps:[
        {type:"intro",title:"Korean Internet Culture",desc:"인터넷\n→ internet\n\nKorea: world's most connected country.\nOnline culture and vocabulary.",goals:["Learn 10 internet/SNS words","Understand Korean online culture","Talk about social media","Use digital vocabulary naturally"]},
        {type:"teach",trg:"인터넷",src:"internet",pos:"noun",gender:null,phonetic:"in-teo-net",note:"Konglish from English 'internet.'\n한국은 인터넷 강국이에요.\nKorea is an internet powerhouse.",example:"A: 요즘 인터넷으로 뭐 해요? B: 주로 뉴스를 보고 영상도 봐요. A: 한국 인터넷이 빠르다면서요? B: 네, 세계에서 제일 빠른 편이에요. A: 저도 한국에서 써 보고 싶어요. B: 진짜 빨라서 놀랄 거예요.",exampleSrc:"A: What do you do on the internet these days? B: I mainly watch news and videos. A: I heard Korean internet is fast? B: Yes, it tends to be the fastest in the world. A: I want to try using it in Korea too. B: You will be surprised because it is really fast.",funFact:"A Konglish loanword adapted from English. Korean has borrowed many modern and tech words."},
        {type:"teach",trg:"댓글",src:"comment (online)",pos:"noun",gender:null,phonetic:"daet-geul",note:"댓(reply/答) + 글(writing).\nReply-writing = online comment.\n댓글을 달다 = to leave a comment.",example:"A: 이 영상에 댓글이 많네요. B: 네, 천 개가 넘었어요. A: 재미있는 댓글이 있어요? B: 웃긴 댓글이 많아서 읽다 보면 시간이 가요. A: 저도 댓글 하나 달아야겠어요. B: 좋은 댓글을 써 주세요.",exampleSrc:"A: There are a lot of comments on this video. B: Yes, it passed a thousand. A: Are there any funny comments? B: There are so many funny ones that time flies while reading them. A: I should leave a comment too. B: Please write a good comment.",funFact:"Built from Chinese characters (Hanja). About 60% of Korean vocabulary has Hanja roots."},
        {type:"teach",trg:"검색하다",src:"to search (online)",pos:"verb",gender:null,phonetic:"geom-saek-ha-da",note:"COMPOUND: 검(examine/檢) + 색(search/索).\nExamine-search = search online.\n네이버에서 검색하다 = search on Naver.",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"teach",trg:"공유하다",src:"to share",pos:"verb",gender:null,phonetic:"gong-yu-ha-da",note:"COMPOUND: 공(public/公) + 유(have/有).\nPublic-have = share.\n링크를 공유하다 = share a link.",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"teach",trg:"게시판",src:"bulletin board, forum",pos:"noun",gender:null,phonetic:"ge-si-pan",note:"COMPOUND: 게(put up/揭) + 시(show/示) + 판(board/板).\nPut-up-show-board = bulletin board.",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"teach",trg:"카톡",src:"KakaoTalk (messaging app)",pos:"noun",gender:null,phonetic:"ka-tok",note:"Short for 카카오톡.\nKorea's #1 messaging app.\nUsed by 90%+ of Koreans.",example:"A: 카톡 써요? B: 당연하죠. 한국에서는 다 카톡을 써요. A: 저한테 카톡 보내 주세요. B: 좋아요, 번호 알려 주세요. A: 010으로 시작하는 번호예요. B: 네, 지금 바로 추가할게요.",exampleSrc:"A: Do you use KakaoTalk? B: Of course. Everyone uses KakaoTalk in Korea. A: Please send me a KakaoTalk. B: Sure, give me your number. A: It is a number starting with 010. B: Okay, I will add you right now.",deepDive:"KakaoTalk dominance in Korea:\n\nUnlike other countries where WhatsApp\nor iMessage dominate, Korea uses KakaoTalk.\n\n- 카톡 보내다 = send a KakaoTalk\n- 카톡 읽다/안 읽다 = read/unread receipts\n- 단톡방 = group chat (단체 톡방)\n- 이모티콘 = emoticons/stickers\n\n카톡 is used for everything:\npersonal, work, government services.",funFact:"Korean nouns don't have articles or plural markers. Context tells you if it's one or many."},
        {type:"teach",trg:"팔로우하다",src:"to follow (social media)",pos:"verb",gender:null,phonetic:"pal-lo-u-ha-da",note:"Konglish from English 'follow.'\n인스타에서 팔로우하다\n= follow on Instagram.",example:"A: 이 연예인 인스타 팔로우해요? B: 아니요, 아직 안 했어요. A: 사진을 정말 잘 올려요. B: 그래요? 지금 팔로우할게요. A: 팔로워가 벌써 백만 명이에요. B: 역시 인기가 많네요.",exampleSrc:"A: Do you follow this celebrity on Instagram? B: No, I have not yet. A: They post really good photos. B: Really? I will follow now. A: They already have a million followers. B: They are indeed very popular.",funFact:"A Konglish loanword adapted from English. Korean has borrowed many modern and tech words."},
        {type:"teach",trg:"업로드하다",src:"to upload",pos:"verb",gender:null,phonetic:"eop-ro-deu-ha-da",note:"Konglish from English 'upload.'\n사진을 업로드하다 = upload a photo.",example:"A: 여행 사진 업로드했어요? B: 아직이요. 고르는 중이에요. A: 빨리 올려 주세요. 보고 싶어요. B: 오늘 밤에 업로드할게요. A: 인스타에 올려요? B: 네, 인스타하고 블로그에 둘 다 올릴 거예요.",exampleSrc:"A: Did you upload the travel photos? B: Not yet. I am choosing them. A: Please post them soon. I want to see. B: I will upload tonight. A: Will you post on Instagram? B: Yes, I will post on both Instagram and my blog.",funFact:"A Konglish loanword adapted from English. Korean has borrowed many modern and tech words."},
        {type:"teach",trg:"구독하다",src:"to subscribe",pos:"verb",gender:null,phonetic:"gu-dok-ha-da",note:"COMPOUND: 구(seek/求) + 독(read/讀).\nSeek-read = subscribe.\n유튜브 채널을 구독하다\n= subscribe to a YouTube channel.",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"teach",trg:"좋아요",src:"like (social media)",pos:"noun",gender:null,phonetic:"jo-a-yo",note:"From 좋다 (to be good) + 아요.\n좋아요를 누르다 = press like.\n좋아요 100개 = 100 likes.",example:"A: 이 사진에 좋아요가 많네요. B: 네, 오백 개나 받았어요. A: 저도 좋아요 눌렀어요. B: 감사합니다. 댓글도 달아 주세요. A: 좋아요만 누르면 안 돼요? B: 댓글도 있으면 더 좋죠.",exampleSrc:"A: This photo has a lot of likes. B: Yes, it got five hundred. A: I pressed like too. B: Thank you. Please leave a comment too. A: Is it not enough to just press like? B: It is even better with comments too.",funFact:"Korean nouns don't have articles or plural markers. Context tells you if it's one or many."},
        {type:"mc",q:"댓글 means:",opts:["Online comment","Social media","Search result","Website"],ans:"Online comment",hint:"댓(reply) + 글(writing) = reply-writing."},
        {type:"match",pairs:[{trg:"검색하다",src:"to search"},{trg:"공유하다",src:"to share"},{trg:"팔로우하다",src:"to follow"},{trg:"업로드하다",src:"to upload"}]},
        {type:"mc",q:"카톡 is short for:",opts:["카카오톡 (KakaoTalk)","카페 토크 (Cafe Talk)","카메라 톡 (Camera Talk)","카드 토큰 (Card Token)"],ans:"카카오톡 (KakaoTalk)",hint:"Korea's dominant messaging app, used by over 90% of Koreans."},
        {type:"fb",opts:["검색","댓글","공유","업로드"],hint:"Looking for information online on Naver.",s:"네이버에서 {1}했어요. 좋은 식당을 찾았어요.\n(I ___ on Naver. I found a good restaurant.)",a:"검색"},
        {type:"mc",q:"게시판 literally means:",opts:["Put-up-show-board","Talk-write-page","Read-see-screen","Type-send-post"],ans:"Put-up-show-board",hint:"게(put up) + 시(show) + 판(board)."},
        {type:"fb",opts:["구독","검색","댓글","공유"],hint:"YouTubers always ask viewers to do this to their channel.",s:"이 유튜브 채널을 {1}하세요!\n(Please ___ to this YouTube channel!)",a:"구독"},
        {type:"drag_fill",hint:"First put the photo online, then let a friend see it.",s:"인스타에 사진을 {1}하고 친구한테 {2}했어요.\n(I ___ed a photo on Instagram and ___ed it with a friend.)",blanks:{"1":"업로드","2":"공유"},pool:["업로드","공유","검색","팔로우","댓글"]},
        {type:"fb",opts:["댓글","검색","카톡","업로드"],hint:"Written feedback below an online video.",s:"이 영상에 {1}을 달아 주세요.\n(Please leave a ___ on this video.)",a:"댓글"},
        {type:"match",pairs:[{trg:"인터넷",src:"internet"},{trg:"구독하다",src:"to subscribe"},{trg:"좋아요",src:"like (social media)"},{trg:"게시판",src:"forum/bulletin board"}]},
        {type:"drag_fill",hint:"Two things YouTubers always ask for at the end of videos.",s:"이 영상이 재미있으면 {1}를 누르고 {2}해 주세요.\n(If this video is fun, press ___ and please ___.)",blanks:{"1":"좋아요","2":"구독"},pool:["좋아요","구독","댓글","검색","카톡"]},
        {type:"mc",q:"친구가 카톡으로 링크를 공유했어요.\n그래서 검색 안 해도 돼요.\n(My friend shared a link via KakaoTalk.\nSo I do not need to search.)\nWhy does the speaker not need to search?",opts:["The friend already shared the link","The friend subscribed","The internet is down","The forum was closed"],ans:"The friend already shared the link",hint:"공유했어요 = shared. The link was already provided."}
  ]},
  {id:"kou16l2",title:"-(ㄴ)다고 하다",icon:"🗣️",xp:26,board:true,steps:[
        {type:"intro",title:"Reporting What Someone Said",desc:"-(ㄴ)다고 하다\n→ someone said that...\n\n뭐라고 했어요?\n→ What did they say?\n\nHow to report statements.",goals:["Use -(ㄴ)다고 하다 for reported speech","Know verb vs adjective vs noun forms","Report what others said","Understand shortened forms"]},
        {type:"tip",title:"Indirect Speech: Statements",deepDive:"The full pattern:\n\nDirect speech:\n민수: '나는 한국 사람이에요.'\n\nIndirect speech:\n민수가 한국 사람이라고 했어요.\n(Minsu said he's Korean.)\n\nThe quotation particle changes:\n- Verb: -(ㄴ/는)다고\n- Adjective: -다고\n- Noun+이다: -(이)라고\n- 아니다: 아니라고\n\n하다 can be replaced with:\n말하다 (say/speak)\n이야기하다 (tell/talk)",text:"For verbs: -(ㄴ/는)다고 하다\nPresent: 간다고 해요 (says they go)\nPast: 갔다고 해요 (says they went)\nFuture: 갈 거라고 해요 (says they will go)\n\nFor adjectives: -다고 하다\nPresent: 크다고 해요 (says it's big)\nPast: 컸다고 해요 (says it was big)\n\nFor nouns + 이다: -(이)라고 하다\n학생이라고 해요 (says they're a student)"},
        {type:"teach",trg:"전하다",src:"to relay, to pass on",pos:"verb",gender:null,phonetic:"jeon-ha-da",note:"COMPOUND: 전(transmit/傳) + 하다.\n메시지를 전하다 = pass on a message.\n전해 주세요 = please relay it.",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"mc",q:"민수가 한국에 간다고 했어요 means:",opts:["Minsu said he is going to Korea","Minsu is going to Korea","Minsu asked about Korea","I told Minsu about Korea"],ans:"Minsu said he is going to Korea",hint:"-(ㄴ)다고 했어요 = said that. Reporting what Minsu stated."},
        {type:"fb",opts:["다고","냐고","라고","자고"],hint:"Reporting a friend's statement about coming. Verb + statement ending.",s:"친구가 내일 온{1} 했어요.\n(My friend said they are coming tomorrow.)",a:"다고"},
        {type:"mc",q:"이 음식이 맛있다고 해요 means:",opts:["They say this food is delicious","I said the food is delicious","Is the food delicious?","Make the food delicious"],ans:"They say this food is delicious",hint:"맛있다고 해요 = they say it is delicious. Adjective reported statement."},
        {type:"fb",opts:["다고","냐고","라고","자고"],hint:"Reporting what the teacher stated about the past exam. Past adjective.",s:"선생님이 시험이 어려웠{1} 했어요.\n(The teacher said the exam was hard.)",a:"다고"},
        {type:"mc",q:"학생이라고 했어요 vs 학생이다고 했어요.\nWhich is correct?",opts:["학생이라고 (noun+이다 uses -(이)라고)","학생이다고 (standard form)","Both are correct","Neither is correct"],ans:"학생이라고 (noun+이다 uses -(이)라고)",hint:"Nouns use -(이)라고, not -다고. This is specific to the copula 이다."},
        {type:"fb",opts:["라고","다고","냐고","자고"],hint:"Reporting a noun (의사). Vowel-ending noun uses 라고.",s:"의사{1} 했어요. 자기 직업이요.\n(They said they are a doctor. Their job.)",a:"라고"},
        {type:"tip",title:"Shortened Forms",deepDive:"Common shortened forms:\n\nFull → Short:\n간다고 해요 → 간대요\n먹는다고 해요 → 먹는대요\n좋다고 해요 → 좋대요\n학생이라고 해요 → 학생이래요\n아니라고 해요 → 아니래요\n\n온다고 했어요 → 온댔어요 (past)\n맛있다고 했어요 → 맛있댔어요 (past)",text:"In casual speech, 하다 is often dropped:\n\n간다고 해요 → 간대요 (says they go)\n맛있다고 해요 → 맛있대요 (says it's tasty)\n학생이라고 해요 → 학생이래요\n\nThese shortened forms are very common\nin spoken Korean and online."},
        {type:"mc",q:"맛있대요 is the shortened form of:",opts:["맛있다고 해요","맛있냐고 해요","맛있으라고 해요","맛있자고 해요"],ans:"맛있다고 해요",hint:"Statements: -다고 해요 shortens to -대요."},
        {type:"match",pairs:[{trg:"간다고 해요",src:"says they go (verb)"},{trg:"좋다고 해요",src:"says it's good (adj)"},{trg:"학생이라고 해요",src:"says they're a student (noun)"},{trg:"갔다고 해요",src:"says they went (past)"}]},
        {type:"drag_fill",hint:"A asks what was said (뭐 + 라고). B reports a verb statement.",s:"A: 뭐{1} 했어요?\nB: 내일 온{2} 했어요.\n(A: What did they say?\nB: They said they are coming tomorrow.)",blanks:{"1":"라고","2":"다고"},pool:["라고","다고","냐고","자고","이라고"]},
        {type:"fb",opts:["다고","냐고","라고","자고"],hint:"The news reported a weather statement. Verb present tense.",s:"뉴스에서 내일 비가 온{1} 했어요.\n(The news said it will rain tomorrow.)",a:"다고"},
        {type:"fb",opts:["다고","냐고","라고","자고"],hint:"Comments report an adjective statement. 재미없다 + statement ending.",s:"댓글에 이 영화가 재미없{1} 해요.\n(The comments say this movie is not fun.)",a:"다고"},
        {type:"mc",q:"친구가 카톡으로 서울에 도착했다고 전해 줬어요.\n(My friend relayed via KakaoTalk that they arrived in Seoul.)\nWhich TWO patterns are combined?",opts:["Reported statement -다고 + benefactive -아/어 주다","Reported question -냐고 + honorific -(으)시-","Reported command -(으)라고 + past tense","Reported suggestion -자고 + -게 되다"],ans:"Reported statement -다고 + benefactive -아/어 주다",hint:"전해 줬어요 combines 전하다 with -아/어 주다 (doing for someone). The content is -다고."},
        {type:"drag_fill",hint:"Both sentences report statements. First: verb past. Second: adjective.",s:"동생이 학교에서 상을 받았{1} 했어요. 엄마가 기뻐하신{2} 했어요.\n(My sibling said they won an award at school. Mom said she is happy.)",blanks:{"1":"다고","2":"다고"},pool:["다고","냐고","라고","자고","이라고"]},
        {type:"mc",q:"인터넷에서 검색했는데 이 가게가 맛집이래요.\n(I searched online and they say this place is a famous restaurant.)\nWhat does 맛집이래요 break down to?",opts:["맛집이라고 해요 (noun + 이라고, shortened)","맛집이다고 해요 (verb + 다고)","맛집이냐고 해요 (question form)","맛집이자고 해요 (suggestion form)"],ans:"맛집이라고 해요 (noun + 이라고, shortened)",hint:"맛집 is a noun. Noun + 이라고 해요 shortens to 이래요."},
        {type:"fb",opts:["다고","냐고","라고","자고"],hint:"People are making a statement about quality. Adjective statement ending.",s:"게시판에 올려서 사람들이 좋{1} 해요.\n(I posted on the forum and people say it is good.)",a:"다고"},
        {type:"drag_fill",hint:"Friend reported a statement (adjective). Then shared content for my benefit.",s:"친구가 맛있{1} 했어요. 그래서 카톡으로 링크를 {2}해 줬어요.\n(My friend said it is tasty. So they shared the link via KakaoTalk for me.)",blanks:{"1":"다고","2":"공유"},pool:["다고","냐고","공유","검색","라고"]},
        {type:"fb",opts:["있냐고","있다고","있자고","있라고"],hint:"-냐고 하다 = reported question. Asking whether something is the case.",s:"친구가 내일 시간이 {1} 물어봤어요.\n(My friend asked whether I have time tomorrow.)",a:["있냐고"]},
        {type:"mc",q:"엄마가 밥을 먹었냐고 하셨어요.\n(Mom asked whether I ate.)",opts:["-냐고 하다 (reported question)","-다고 하다 (reported statement)","-(으)라고 하다 (reported command)","-자고 하다 (reported suggestion)"],ans:"-냐고 하다 (reported question)",hint:"-냐고 reports a question. Mom asked: did you eat?"}
  ]},
  {id:"kou16l3",title:"-냐고 하다",icon:"❓",xp:24,board:true,steps:[
        {type:"intro",title:"Reporting Questions",desc:"-냐고 하다\n→ someone asked whether...\n\nReport questions others asked.\nVery common in daily speech.",goals:["Use -냐고 하다 for reported questions","Know verb/adjective/noun forms","Report questions naturally","Distinguish from reported statements"]},
        {type:"teach",trg:"-냐고 하다",src:"asked whether, asked if",pos:"verb",gender:null,phonetic:"-nya-go ha-da",note:"Verb/adj stem + -냐고 하다.\n가냐고 했어요 = asked if going.\n\nNoun + -(이)냐고 하다.\n학생이냐고 했어요 = asked if a student.",example:"A: 엄마가 뭐라고 하셨어요? B: 밥 먹었냐고 물어보셨어요. A: 뭐라고 대답했어요? B: 아직 안 먹었다고 했어요. A: 그래서 엄마가 뭐라고 하셨어요? B: 빨리 먹으라고 하셨어요.",exampleSrc:"A: What did mom say? B: She asked if I had eaten. A: What did you answer? B: I said I had not eaten yet. A: So what did mom say then? B: She told me to eat quickly.",deepDive:"Question reporting patterns:\n\nVerb: stem + -냐고\n가냐고 (asked if going)\n먹냐고 (asked if eating)\n했냐고 (asked if did)\n\nAdjective: stem + -냐고 or -(으)냐고\n좋냐고 / 좋으냐고 (asked if good)\n맛있냐고 (asked if tasty)\n\nNoun: + (이)냐고\n학생이냐고 (asked if student)\n한국 사람이냐고 (asked if Korean)\n\nShortened: -냐고 해요 → -냬요",funFact:"A 하다 verb — noun + 하다 (to do). This pattern creates hundreds of verbs from Sino-Korean nouns."},
        {type:"teach",trg:"물어보다",src:"to ask (a question)",pos:"verb",gender:null,phonetic:"mul-eo-bo-da",note:"물(ask) + 어 + 보다(try/see).\n물어봤어요 = I asked.\nMore casual than 질문하다.",example:"A: 선생님한테 물어봤어요? B: 아니요, 아직 못 물어봤어요. A: 왜요? 시간이 없었어요? B: 수업 끝나고 바로 가셔서요. A: 내일 다시 물어보세요. B: 네, 내일 꼭 물어볼게요.",exampleSrc:"A: Did you ask the teacher? B: No, I have not asked yet. A: Why? Did you not have time? B: The teacher left right after class. A: Please ask again tomorrow. B: Yes, I will definitely ask tomorrow.",funFact:"A 하다 verb — noun + 하다 (to do). This pattern creates hundreds of verbs from Sino-Korean nouns."},
        {type:"mc",q:"어디 가냐고 했어요 means:",opts:["They asked where I am going","They said they are going somewhere","They told me to go","They suggested going"],ans:"They asked where I am going",hint:"-냐고 했어요 reports a question someone asked."},
        {type:"fb",opts:["봤냐고","봤다고","보라고","보자고"],hint:"Reporting a question about whether I took the exam. Past verb + question ending.",s:"친구가 시험 {1} 했어요.\n(My friend asked if I took the exam.)",a:"봤냐고"},
        {type:"mc",q:"Statement vs Question: 간다고 vs 가냐고:",opts:["-다고 = says going, -냐고 = asks if going","-다고 and -냐고 mean the same thing","Both report statements","Both report questions"],ans:"-다고 = says going, -냐고 = asks if going",hint:"One reports a fact stated, the other reports a question asked."},
        {type:"fb",opts:["냐고","다고","라고","자고"],hint:"The teacher asked a question about homework. Reported question ending.",s:"선생님이 숙제 했{1} 물어봤어요.\n(The teacher asked if I did the homework.)",a:"냐고"},
        {type:"mc",q:"한국 사람이냐고 했어요 means:",opts:["They asked if I am Korean","They said I am Korean","They told me to be Korean","Korean people said something"],ans:"They asked if I am Korean",hint:"-(이)냐고 reports a question. Noun + 이다 question form."},
        {type:"fb",opts:["냐고","다고","라고","자고"],hint:"Mom asked a question about eating. Past verb question ending.",s:"엄마가 밥 먹었{1} 물어봤어요.\n(Mom asked if I ate.)",a:"냐고"},
        {type:"mc",q:"맛있냬요 is the shortened form of:",opts:["맛있냐고 해요","맛있다고 해요","맛있으라고 해요","맛있자고 해요"],ans:"맛있냐고 해요",hint:"Questions: -냐고 해요 shortens by merging the middle syllables."},
        {type:"drag_fill",hint:"A: What did they ask? (뭐라고) B: reported question about having time.",s:"A: 친구가 뭐{1} 물어봤어요?\nB: 내일 시간 있{2} 물어봤어요.\n(A: What did your friend ask?\nB: They asked if I have time tomorrow.)",blanks:{"1":"라고","2":"냐고"},pool:["라고","냐고","다고","자고","으라고"]},
        {type:"match",pairs:[{trg:"간다고 (statement)",src:"says going"},{trg:"가냐고 (question)",src:"asks if going"},{trg:"가라고 (command)",src:"tells to go"},{trg:"가자고 (suggestion)",src:"suggests going"}]},
        {type:"mc",q:"외국인이냐고 물어봤어요.\nThis person:",opts:["Asked if I am a foreigner","Told me I am a foreigner","Said they are a foreigner","Suggested being a foreigner"],ans:"Asked if I am a foreigner",hint:"-(이)냐고 물어봤어요 = asked whether. A question about identity."},
        {type:"fb",opts:["냐고","다고","라고","자고"],hint:"The customer asked a price question. Reported question ending.",s:"손님이 이거 얼마{1} 물어봤어요.\n(The customer asked how much this is.)",a:"냐고"},
        {type:"fb",opts:["검색하냐고","검색한다고","검색하라고","검색하자고"],hint:"Sibling asked a question about what I am doing online. Question form of 검색하다.",s:"동생이 인터넷에서 뭐 {1} 물어봤어요.\n(My sibling asked what I am searching online.)",a:"검색하냐고"},
        {type:"mc",q:"카톡으로 언제 오냐고 물어봤는데 아직 답이 없어요.\n(I asked via KakaoTalk when they are coming, but there is no reply yet.)\nWhich patterns appear here?",opts:["Reported question -냐고 + contrast -는데","Reported statement -다고 + conditional -(으)면","Reported command -(으)라고 + reason -아서","Reported suggestion -자고 + contrast -지만"],ans:"Reported question -냐고 + contrast -는데",hint:"오냐고 = reported question. -는데 gives background before the contrast (no reply)."},
        {type:"drag_fill",hint:"First sentence: reported question. Second: reported statement as answer.",s:"친구가 게시판에 뭐 올렸{1} 물어봤어요. 새 영상을 업로드했{2} 대답했어요.\n(My friend asked what I posted on the forum. I answered that I uploaded a new video.)",blanks:{"1":"냐고","2":"다고"},pool:["냐고","다고","라고","자고","이냐고"]},
        {type:"mc",q:"댓글에서 이 가게 맛있냬요.\n가 봤냐고도 물어봤어요.\n(In the comments they ask if this place is tasty.\nThey also asked if I have been there.)\nHow many reported questions?",opts:["Two: 맛있냬요 and 가 봤냐고","One: only 맛있냬요","One: only 가 봤냐고","None"],ans:"Two: 맛있냬요 and 가 봤냐고",hint:"맛있냬요 = 맛있냐고 해요 (shortened). 가 봤냐고 = asked if visited. Both reported questions."},
        {type:"fb",opts:["냐고","다고","라고","자고"],hint:"The follower asked a question about location. Reported question ending.",s:"팔로워가 이 사진 어디서 찍었{1} 물어봤어요.\n(A follower asked where I took this photo.)",a:"냐고"},
        {type:"drag_fill",hint:"Reviews: adjective statement. Owner: honorific command (eat a lot).",s:"리뷰에서 맛있{1} 해서 갔는데, 사장님이 많이 드시{2} 하셨어요.\n(Reviews said it is tasty so I went, and the owner told me to eat a lot.)",blanks:{"1":"다고","2":"라고"},pool:["다고","라고","냐고","자고","이라고"]},
        {type:"drag_fill",hint:"-냐고 (reported question) + -(으)시- (honorific for teacher) + -는데 (contrast).",s:"선생님이 왜 {1} 하셨는데 대답을 못 {2}.\n(The teacher asked why I was late but I could not answer.)",blanks:{"1":"늦었냐고","2":"했어요"},pool:["늦었냐고","했어요","늦었다고","해요","늦으라고","하는데"]},
        {type:"mc",q:"의사가 어디가 아프냐고 물어봤어요.\n(The doctor asked where it hurts.)",opts:["-냐고 (reported question)","-다고 (reported statement)","-(으)라고 (reported command)","-자고 (reported suggestion)"],ans:"-냐고 (reported question)",hint:"The doctor ASKED (question) = -냐고."}
  ]},
  {id:"kou16l4",title:"-(으)라고/자고",icon:"📣",xp:24,board:true,steps:[
        {type:"intro",title:"Reporting Commands & Suggestions",desc:"-(으)라고 하다\n→ told someone to...\n\n-자고 하다\n→ suggested that...\n\nComplete the indirect speech system.",goals:["Use -(으)라고 for reported commands","Use -자고 for reported suggestions","Complete all 4 indirect speech types","Contrast commands vs suggestions"]},
        {type:"teach",trg:"-(으)라고 하다",src:"told to, ordered to",pos:"verb",gender:null,phonetic:"-(eu)ra-go ha-da",note:"Verb stem + (으)라고 하다.\nVowel stem: 라고.\nConsonant stem: 으라고.\n가라고 했어요 = told me to go.",example:"A: 의사가 뭐라고 했어요? B: 술을 마시지 말라고 했어요. A: 운동은요? B: 매일 운동하라고 했어요. A: 약도 먹으라고 했어요? B: 네, 하루에 세 번 먹으라고 했어요.",exampleSrc:"A: What did the doctor say? B: The doctor told me not to drink alcohol. A: What about exercise? B: The doctor told me to exercise every day. A: Did they also tell you to take medicine? B: Yes, they told me to take it three times a day.",deepDive:"Commands use imperative base:\n\n가다 → 가라고 (told to go)\n먹다 → 먹으라고 (told to eat)\n하다 → 하라고 (told to do)\n오다 → 오라고 (told to come)\n\nNegative commands:\n가지 말라고 (told not to go)\n먹지 말라고 (told not to eat)\n\nShortened: -(으)라고 해요 → -(으)래요",funFact:"A 하다 verb — noun + 하다 (to do). This pattern creates hundreds of verbs from Sino-Korean nouns."},
        {type:"teach",trg:"-자고 하다",src:"suggested, proposed",pos:"verb",gender:null,phonetic:"-ja-go ha-da",note:"Verb stem + 자고 하다.\n가자고 했어요 = suggested going.\n같이 먹자고 했어요\n= suggested eating together.",example:"A: 주말에 뭐 할까요? B: 친구가 등산 가자고 했어요. A: 등산 좋아해요? B: 네, 같이 가자고 했는데 갈래요? A: 좋아요. 몇 시에 만나자고 했어요? B: 아침 아홉 시에 만나자고 했어요.",exampleSrc:"A: What shall we do this weekend? B: A friend suggested going hiking. A: Do you like hiking? B: Yes, they suggested going together. Do you want to come? A: Sure. What time did they suggest meeting? B: They suggested meeting at nine in the morning.",deepDive:"Suggestions use -자 base:\n\n가다 → 가자고 (suggested going)\n먹다 → 먹자고 (suggested eating)\n하다 → 하자고 (suggested doing)\n\nShortened: -자고 해요 → -재요\n\n가자고 해요 → 가재요\n먹자고 해요 → 먹재요",funFact:"A 하다 verb — noun + 하다 (to do). This pattern creates hundreds of verbs from Sino-Korean nouns."},
        {type:"teach",trg:"참석하다",src:"to attend, to participate",pos:"verb",gender:null,phonetic:"cham-seok-ha-da",note:"COMPOUND: 참(join/參) + 석(seat/席).\nJoin-seat = attend.\n회의에 참석하다 = attend a meeting.",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"mc",q:"선생님이 공부하라고 했어요 means:",opts:["The teacher told us to study","The teacher said they study","The teacher asked if we study","The teacher suggested studying"],ans:"The teacher told us to study",hint:"-(으)라고 = reported command. The teacher ordered/instructed."},
        {type:"fb",opts:["자고","라고","다고","냐고"],hint:"My friend suggested watching a movie. Suggestion ending.",s:"친구가 같이 영화 보{1} 했어요.\n(My friend suggested watching a movie together.)",a:"자고"},
        {type:"mc",q:"엄마가 빨리 오라고 했어요 vs 엄마가 빨리 오자고 했어요.\nWhat is the difference?",opts:["First: mom told to come. Second: mom suggested coming.","Both mean the same thing","First is a suggestion, second is a command","Both are questions"],ans:"First: mom told to come. Second: mom suggested coming.",hint:"-(으)라고 = command (told to). -자고 = suggestion (let's)."},
        {type:"fb",opts:["하라고","하자고","한다고","하냐고"],hint:"The doctor gave a medical order. Command ending.",s:"의사가 운동{1} 했어요. 건강을 위해서요.\n(The doctor told me to exercise. For my health.)",a:"하라고"},
        {type:"mc",q:"가지 말라고 했어요 means:",opts:["They told me not to go","They suggested not going","They said they are not going","They asked if I am going"],ans:"They told me not to go",hint:"-지 말라고 = reported negative command."},
        {type:"tip",title:"The Complete Indirect Speech System",text:"4 types of reported speech:\n\n1. Statement: -(ㄴ)다고\n   간다고 해요 (says going)\n\n2. Question: -냐고\n   가냐고 해요 (asks if going)\n\n3. Command: -(으)라고\n   가라고 해요 (tells to go)\n\n4. Suggestion: -자고\n   가자고 해요 (suggests going)\n\nAll can use 하다, 말하다, or 이야기하다."},
        {type:"fb",opts:["하라고","하자고","한다고","하냐고"],hint:"Giving an instruction to a younger sibling. Command ending.",s:"동생에게 숙제 {1} 했어요.\n(I told my younger sibling to do homework.)",a:"하라고"},
        {type:"mc",q:"같이 점심 먹자고 했어요. This is a:",opts:["Reported suggestion","Reported command","Reported statement","Reported question"],ans:"Reported suggestion",hint:"-자고 = suggestion. Someone proposed eating lunch together."},
        {type:"drag_fill",hint:"Both are commands. 하다 → 하라고. 읽다 → 읽으라고 (consonant stem).",s:"선생님이 조용히 {1} 했어요. 그리고 책을 읽{2} 했어요.\n(The teacher told us to be quiet. And told us to read the book.)",blanks:{"1":"하라고","2":"으라고"},pool:["하라고","으라고","한다고","읽냐고","하자고"]},
        {type:"match",pairs:[{trg:"-(ㄴ)다고",src:"reports statement"},{trg:"-냐고",src:"reports question"},{trg:"-(으)라고",src:"reports command"},{trg:"-자고",src:"reports suggestion"}]},
        {type:"mc",q:"Shortened forms: 간대요, 가냬요, 가래요, 가재요.\nMatch the full forms:",opts:["간다고, 가냐고, 가라고, 가자고 (all correct)","Only 간대요 is a real form","These are all the same meaning","None of these exist"],ans:"간다고, 가냐고, 가라고, 가자고 (all correct)",hint:"-대요(statement), -냬요(question), -래요(command), -재요(suggestion)."},
        {type:"fb",opts:["자고","라고","다고","냐고"],hint:"Friend proposed a weekend hiking plan. Suggestion ending.",s:"친구가 주말에 등산 가{1} 했어요.\n(My friend suggested going hiking this weekend.)",a:"자고"},
        {type:"fb",opts:["참석하라고","참석하자고","참석한다고","참석하냐고"],hint:"The CEO gave an order about the meeting. Command + honorific.",s:"사장님이 회의에 {1} 말씀하셨어요.\n(The CEO told us to attend the meeting.)",a:"참석하라고"},
        {type:"drag_fill",hint:"Mom gave a command (sleep early). Dad made a suggestion (walk together).",s:"엄마가 일찍 자{1} 했어요. 아빠는 같이 산책 가{2} 했어요.\n(Mom told me to sleep early. Dad suggested going for a walk together.)",blanks:{"1":"라고","2":"자고"},pool:["라고","자고","다고","냐고","이라고"]},
        {type:"mc",q:"카톡으로 같이 저녁 먹자고 했는데 바쁘다고 했어요.\n(I suggested via KakaoTalk to eat dinner together,\nbut they said they are busy.)\nWhich TWO indirect speech types appear?",opts:["Suggestion -자고 + Statement -다고","Command -(으)라고 + Question -냐고","Statement -다고 + Question -냐고","Command -(으)라고 + Suggestion -자고"],ans:"Suggestion -자고 + Statement -다고",hint:"먹자고 = suggestion. 바쁘다고 = statement. Two different types in one sentence."},
        {type:"fb",opts:["말라고","말자고","말다고","말냐고"],hint:"They told me NOT to leave comments. Negative command in reported speech.",s:"게시판에 댓글 달지 {1} 했어요.\n(They told me not to leave comments on the forum.)",a:"말라고"},
        {type:"mc",q:"친구가 같이 영화를 보자고 했어요.\n(My friend suggested watching a movie together.)",opts:["-자고 하다 (suggestion)","-(으)라고 하다 (command)","-냐고 하다 (question)","-다고 하다 (statement)"],ans:"-자고 하다 (suggestion)",hint:"-자고 reports a suggestion/proposal: let us do X together."}
  ]},
  {id:"kou16l5",title:"-(으)시- 존댓말",icon:"🙇",xp:24,board:true,steps:[
        {type:"intro",title:"Deepening Honorifics",desc:"-(으)시-\n→ honorific marker\n\nMake verbs respectful.\nEssential for polite Korean.",goals:["Use -(으)시- honorific marker","Know when to use honorifics","Apply to common verbs","Understand special honorific words"]},
        {type:"teach",trg:"-(으)시-",src:"honorific verb marker",pos:"part",gender:null,phonetic:"-(eu)si-",note:"Insert between stem and ending.\nVowel stem: 시\nConsonant stem: 으시\n가다 → 가시다 → 가세요.\n먹다 → 잡수시다 (special form).",example:"A: 할머니, 어디 가세요? B: 시장에 가요. 뭐 필요해? A: 과일 좀 사 주세요. B: 그래, 뭐 드시고 싶어? A: 사과 있으면 사 주세요. B: 알았어. 할아버지도 집에 계시니?",exampleSrc:"A: Grandma, where are you going? B: I am going to the market. Do you need anything? A: Please buy some fruit. B: Sure, what do you want to eat? A: If there are apples, please buy some. B: Okay. Is grandpa home too?",deepDive:"-(으)시- conjugation:\n\n가다 → 가시다\n가세요 (present polite)\n가셨어요 (past polite)\n가실 거예요 (future polite)\n\n먹다 → 드시다/잡수시다 (special)\n읽다 → 읽으시다 → 읽으세요\n\nUse for: elders, bosses, teachers,\nstrangers, customers.\nDo NOT use for yourself.",funFact:"Korean particles attach to nouns to show their role in the sentence. The particle, not word order, determines meaning."},
        {type:"tip",title:"Special Honorific Words",deepDive:"The three levels of Korean politeness:\n\n1. 반말 (casual): 가, 먹어, 자\n   For close friends, children, juniors.\n\n2. 해요체 (polite): 가요, 먹어요, 자요\n   Default for most situations.\n\n3. 존댓말 with -(으)시-: 가세요, 드세요\n   For elders, superiors, strangers.\n\n4. 합쇼체 (formal): 가십니다, 드십니다\n   Official situations, news, military.",text:"Some verbs have completely different\nhonorific forms:\n\n먹다 → 드시다/잡수시다 (eat)\n마시다 → 드시다 (drink)\n자다 → 주무시다 (sleep)\n있다 → 계시다 (exist/stay)\n말하다 → 말씀하시다 (speak)\n죽다 → 돌아가시다 (die)\n아프다 → 편찮으시다 (be sick)\n\nThese are called 높임말 (elevated words)."},
        {type:"teach",trg:"말씀",src:"words, speech (honorific)",pos:"noun",gender:null,phonetic:"mal-sseum",note:"Honorific form of 말.\n말씀하시다 = to speak (honorific).\n말씀해 주세요 = please tell me.",example:"A: 사장님이 뭐라고 말씀하셨어요? B: 내일 회의가 있다고 말씀하셨어요. A: 몇 시라고 하셨어요? B: 아침 열 시라고 하셨어요. A: 말씀해 주셔서 감사합니다. B: 아니에요. 중요한 말씀이니까요.",exampleSrc:"A: What did the CEO say? B: They said there is a meeting tomorrow. A: What time did they say? B: They said ten in the morning. A: Thank you for letting me know. B: Not at all. It is important information.",funFact:"Korean nouns don't have articles or plural markers. Context tells you if it's one or many."},
        {type:"mc",q:"할머니, 뭐 드세요? means:",opts:["Grandma, what are you eating? (honorific)","Grandma, what do you give?","What did grandma make?","Grandma, please give me something"],ans:"Grandma, what are you eating? (honorific)",hint:"드시다 = honorific for 먹다/마시다. 드세요 = are you eating (respectful)."},
        {type:"fb",opts:["계세요","있어요","있세요","있으세요"],hint:"있다 becomes a special honorific form for a respected person. Not 있 + 세요.",s:"선생님이 교실에 {1}.\n(The teacher is in the classroom.)",a:"계세요"},
        {type:"mc",q:"할아버지, 잘 주무셨어요? means:",opts:["Grandfather, did you sleep well? (honorific)","Grandfather, are you sleeping?","Did you give grandfather something?","Grandfather is sleeping well"],ans:"Grandfather, did you sleep well? (honorific)",hint:"주무시다 = honorific for 자다 (sleep). 주무셨어요 = past honorific."},
        {type:"fb",opts:["하셨어요","했어요","하시면","해요"],hint:"Asking mother about eating. Honorific past tense of 하다.",s:"어머니, 식사 {1}?\n(Mother, have you eaten?)",a:"하셨어요"},
        {type:"mc",q:"Which is the honorific of 말하다?",opts:["말씀하시다","말해시다","말시하다","말을하시다"],ans:"말씀하시다",hint:"말하다 has a special honorific word, not just adding -(으)시-."},
        {type:"fb",opts:["말씀하셨어요","말했어요","말해요","말하거든요"],hint:"The CEO spoke (honorific past). 말씀하시다 in past tense.",s:"사장님이 {1}. 회의가 있대요.\n(The CEO spoke. They say there is a meeting.)",a:"말씀하셨어요"},
        {type:"mc",q:"You should NEVER use -(으)시- for:",opts:["Yourself (your own actions)","Your teacher","Your grandparents","A customer"],ans:"Yourself (your own actions)",hint:"-(으)시- elevates others. Using it for yourself sounds incorrect."},
        {type:"match",pairs:[{trg:"먹다 → 드시다",src:"eat (honorific)"},{trg:"자다 → 주무시다",src:"sleep (honorific)"},{trg:"있다 → 계시다",src:"be/stay (honorific)"},{trg:"말하다 → 말씀하시다",src:"speak (honorific)"}]},
        {type:"drag_fill",hint:"A uses honorific for grandma. B uses plain form for self.",s:"A: 할머니, 어디 {1}?\nB: 시장에 {2}.\n(A: Grandma, where are you going?\nB: I am going to the market.)",blanks:{"1":"가세요","2":"가요"},pool:["가세요","가요","가시다","갔어요","가는데"]},
        {type:"mc",q:"돌아가셨어요 is the honorific way to say someone:",opts:["Passed away (died)","Came back","Left the room","Got lost"],ans:"Passed away (died)",hint:"돌아가시다 = honorific for 죽다 (die). Very respectful expression."},
        {type:"fb",opts:["세요","어요","시요","서요"],hint:"편찮으시다 = honorific for 아프다. Present polite honorific ending.",s:"할아버지가 편찮으{1}. 병원에 가셨어요.\n(Grandfather is not feeling well. He went to the hospital.)",a:"세요"},
        {type:"mc",q:"선생님이 내일 오시라고 하셨어요.\n(The teacher told us to come tomorrow.)\nWhich patterns are combined?",opts:["Honorific -(으)시- + reported command -(으)라고 + honorific 하셨어요","Only reported command","Only honorific","Reported question + honorific"],ans:"Honorific -(으)시- + reported command -(으)라고 + honorific 하셨어요",hint:"오시라고 = honorific command. 하셨어요 = honorific 하다 in past. Double layers."},
        {type:"drag_fill",hint:"Grandma asked a question (reported question + honorific). Then gave a command.",s:"할머니가 잘 {1} 물어보셨어요. 그리고 밥 많이 {2} 하셨어요.\n(Grandma asked if I am eating well. And told me to eat a lot.)",blanks:{"1":"먹냐고","2":"먹으라고"},pool:["먹냐고","먹으라고","먹는다고","먹자고","있냐고"]},
        {type:"fb",opts:["검색","공유","댓글","업로드"],hint:"Father gave a negative command about looking things up online.",s:"아버지가 인터넷에서 {1}하지 말라고 하셨어요.\n(Father told me not to search on the internet.)",a:"검색"},
        {type:"mc",q:"사장님이 이 자료를 공유하시라고 하셨는데,\n직원이 어디에 올리냐고 물어봤어요.\n(The CEO told us to share this material,\nbut an employee asked where to upload it.)\nHow many constructs from U16?",opts:["3: honorific -(으)시-, command -(으)라고, question -냐고","Only 1: reported command","Only 2: honorific + command","4: all four speech types"],ans:"3: honorific -(으)시-, command -(으)라고, question -냐고",hint:"공유하시라고 = honorific command. 하셨는데 = honorific contrast. 올리냐고 = question."},
        {type:"drag_fill",hint:"First: honorific reported question about eating. Second: honorific reported statement.",s:"할머니가 잘 {1} 물어보셨어요. 건강하{2} 말씀하셨어요.\n(Grandma asked if I am eating well. She said she is healthy.)",blanks:{"1":"먹냐고","2":"다고"},pool:["먹냐고","다고","먹으라고","자고","먹는다고"]},
        {type:"fb",opts:["드셨어요","먹었어요","먹으셨어요","드려요"],hint:"Honorific: 먹다 → 드시다. Past + -(으)시-: 드셨어요.",s:"할머니께서 진지를 {1}.\n(Grandmother had her meal. (honorific))",a:["드셨어요"]},
        {type:"mc",q:"사장님께서 회의에 참석하시겠다고 하셨어요.\n(The president said he would attend the meeting.)",opts:["-(으)시- + -겠- + -다고 + -(으)시-","-(으)시- + -겠- + -냐고 + -(으)시-","-겠- + -다고 + -자고","-(으)시- + -았/었- + -다고"],ans:"-(으)시- + -겠- + -다고 + -(으)시-",hint:"Double honorific: 참석하시겠다 (will attend, hon) + 하셨어요 (said, hon)."},
        {type:"match",pairs:[{trg:"드시다",src:"eat (honorific of 먹다)"},{trg:"주무시다",src:"sleep (honorific of 자다)"},{trg:"계시다",src:"be/exist (honorific of 있다)"},{trg:"돌아가시다",src:"pass away (honorific of 죽다)"}]}
  ]},
  {id:"kou16l6",title:"SNS 한국어",icon:"📲",xp:20,board:true,steps:[
        {type:"intro",title:"Korean Online Slang",desc:"Online Korean is different\nfrom textbook Korean.\n\nAbbreviations, slang, and trends.",goals:["Learn common Korean internet slang","Understand online abbreviations","See how reported speech appears online","Navigate Korean social media"]},
        {type:"tip",title:"Common Korean Internet Abbreviations",deepDive:"More Korean internet culture:\n\n인정 = acknowledged/agreed\n실화? = for real? (실제 화? = real story?)\n갑분싸 = 갑자기 분위기 싸해짐\n   (atmosphere suddenly got cold)\n레전드 = legend (Konglish, amazing thing)\n꿀잼 = honey-fun (super fun)\n노잼 = no-fun (boring)\n\n찐 = real/genuine (from 진짜)\n최고 = the best\n대박 = amazing/jackpot",text:"ㅋㅋㅋ = hahaha (ㅋ = consonant of 크)\nㅎㅎㅎ = hehe (softer laugh)\nㅠㅠ = crying (looks like tears)\nㄱㄱ = go go (let's go)\nㄴㄴ = no no (nope)\nㅇㅇ = yeah yeah (uh-huh)\nㄷㄷ = 덜덜 (shaking/wow)\nㅇㅋ = OK"},
        {type:"teach",trg:"대박",src:"amazing, jackpot, wow",pos:"intj",gender:null,phonetic:"dae-bak",note:"Originally: big gourd (harvest symbol).\nNow: exclamation of amazement.\n대박! = Wow! Amazing!",example:"A: 어제 콘서트 어땠어요? B: 대박이었어요! 진짜 좋았어요. A: 대박! 누가 나왔어요? B: 제가 좋아하는 가수가 깜짝 등장했어요. A: 와, 진짜 대박이네요. B: 네, 평생 잊을 수 없을 거예요.",exampleSrc:"A: How was the concert yesterday? B: It was amazing! It was really good. A: Wow! Who appeared? B: My favorite singer made a surprise appearance. A: Wow, that is really amazing. B: Yes, I will never forget it.",funFact:"Korean has rich exclamations that express subtle emotions. Tone and context determine the exact feeling."},
        {type:"teach",trg:"꿀잼",src:"super fun, hilarious",pos:"noun",gender:null,phonetic:"kkul-jaem",note:"꿀(honey) + 잼(fun, from 재미).\nHoney-fun = super entertaining.\nOpposite: 노잼 (no fun, boring).",example:"A: 이 드라마 봤어요? B: 네, 진짜 꿀잼이에요! A: 그래요? 저도 볼까요? B: 꼭 보세요. 한 번 시작하면 못 멈춰요. A: 그런 드라마가 최고예요. B: 노잼인 줄 알았는데 완전 꿀잼이었어요.",exampleSrc:"A: Did you watch this drama? B: Yes, it is super fun! A: Really? Should I watch it too? B: Definitely watch it. Once you start you cannot stop. A: That kind of drama is the best. B: I thought it would be boring but it was totally hilarious.",funFact:"Korean nouns don't have articles or plural markers. Context tells you if it's one or many."},
        {type:"teach",trg:"인증",src:"proof, verification (online)",pos:"noun",gender:null,phonetic:"in-jeung",note:"COMPOUND: 인(recognize/認) + 증(evidence/證).\n인증샷 = proof photo.\nUsed when posting evidence of something.",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"teach",trg:"공감하다",src:"to relate to, to empathize",pos:"verb",gender:null,phonetic:"gong-gam-ha-da",note:"COMPOUND: 공(together/共) + 감(feel/感).\nTogether-feel = empathize.\n공감 100% = I totally relate!",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"mc",q:"ㅋㅋㅋ in a Korean chat means:",opts:["Laughter (hahaha)","Crying","Anger","Confusion"],ans:"Laughter (hahaha)",hint:"ㅋ is the consonant of 크 (ke-ke), representing laughter."},
        {type:"mc",q:"ㅠㅠ represents:",opts:["Crying eyes (sad/moved)","Laughing eyes","Angry eyes","Sleeping eyes"],ans:"Crying eyes (sad/moved)",hint:"ㅠ looks like tears streaming down."},
        {type:"fb",opts:["꿀잼","노잼","대박","ㅋㅋ"],hint:"What slang word combines a sweet substance with fun (재미)?",s:"이 영화 {1}! 꼭 봐야 해요!\n(This movie is ___! You must watch it!)",a:"꿀잼"},
        {type:"mc",q:"노잼 means:",opts:["Boring (no fun)","Super fun","A type of jam","A music genre"],ans:"Boring (no fun)",hint:"노(no) + 잼(fun/재미) = no fun = boring."},
        {type:"tip",title:"Reported Speech Online",text:"Online, Koreans report what others said:\n\n누가 맛있다고 했어요?\n= Who said it's delicious?\n\n댓글에 좋다고 써 있어요.\n= The comments say it's good.\n\n친구가 가자고 카톡 보냈어요.\n= My friend sent a KakaoTalk suggesting we go.\n\nIndirect speech is everywhere in\nKorean social media and messaging."},
        {type:"match",pairs:[{trg:"ㅋㅋㅋ",src:"hahaha"},{trg:"ㅠㅠ",src:"crying"},{trg:"대박",src:"amazing"},{trg:"꿀잼",src:"super fun"}]},
        {type:"fb",opts:["자고","라고","다고","냐고"],hint:"Friend proposed meeting tomorrow. Suggestion ending.",s:"친구가 카톡으로 내일 만나{1} 했어요.\n(My friend suggested via KakaoTalk to meet tomorrow.)",a:"자고"},
        {type:"mc",q:"댓글에 맛있대요 means:",opts:["The comments say it is delicious","The comments ask if it is delicious","I commented that it is delicious","Delete the comment"],ans:"The comments say it is delicious",hint:"맛있대요 = 맛있다고 해요 (shortened). Reports what the comments state."},
        {type:"fb",opts:["좋아요","댓글","검색","구독"],hint:"The social media reaction button. People press it when they agree.",s:"이 게시판 글에 {1}이 많아요. 다들 공감하나 봐요.\n(This forum post has a lot of ___. Everyone seems to relate.)",a:"좋아요"},
        {type:"drag_fill",hint:"B exclaims amazement. Then reports what comments state (adjective shortened form).",s:"A: 이 식당 어때? B: {1}! 댓글에 맛있{2}.\n(A: How is this restaurant? B: ___! The comments say it is delicious.)",blanks:{"1":"대박","2":"대요"},pool:["대박","대요","ㅋㅋ","냬요","래요"]},
        {type:"fb",opts:["구독","검색","팔로우","공유"],hint:"Friend gave a command about a YouTube channel. What do you do to channels?",s:"친구가 이 유튜버를 {1}하라고 했어요. 진짜 재미있대요.\n(My friend told me to ___ to this YouTuber. They say they are really fun.)",a:"구독"},
        {type:"mc",q:"게시판에서 노잼이래요. 그런데 댓글에는 꿀잼이라고도 해요.\n(The forum says it is boring. But comments also say it is super fun.)\nWhat do 노잼이래요 and 꿀잼이라고 have in common?",opts:["Both use -(이)라고: noun reporting. 이래요 is shortened.","Both use -다고: adjective reporting","Both use -냐고: question reporting","They use different patterns"],ans:"Both use -(이)라고: noun reporting. 이래요 is shortened.",hint:"노잼 and 꿀잼 are used as noun predicates. Noun + 이라고 해요. 이래요 = shortened form."},
        {type:"drag_fill",hint:"First: honey-fun slang. Second: sending content to a friend.",s:"이 영상 {1}이에요 ㅋㅋ 친구한테 {2}했어요.\n(This video is super fun haha. I shared it with my friend.)",blanks:{"1":"꿀잼","2":"공유"},pool:["꿀잼","노잼","공유","검색","구독"]},
        {type:"mc",q:"인스타에 인증샷을 업로드했어요. 대박이라고 했어요.\n(I uploaded a proof photo on Instagram. They said it is amazing.)\nWhich U16 vocabulary and grammar appear?",opts:["인증 (proof) + 업로드하다 (upload) + noun reporting -(이)라고","검색하다 (search) + adjective reporting -다고","구독하다 (subscribe) + question reporting -냐고","댓글 (comment) + command reporting -(으)라고"],ans:"인증 (proof) + 업로드하다 (upload) + noun reporting -(이)라고",hint:"인증샷 uses 인증. 업로드했어요 uses 업로드하다. 대박이라고 = noun + 이라고."},
        {type:"fb",opts:["받아서","받는데","받으면","받아도"],hint:"-아/어서 (cause/result): getting likes caused good feeling.",s:"SNS에서 좋아요를 많이 {1} 기분이 좋아졌어요.\n(I got many likes on SNS and felt good.)",a:["받아서"]},
        {type:"mc",q:"요즘 한국 청소년들은 SNS를 많이 하는 편이에요.\n(Korean teenagers these days tend to use SNS a lot.)",opts:["-는 편이다","-고 있다","-게 되다","-기로 하다"],ans:"-는 편이다",hint:"-는 편이다 = tendency. General statement about a group."}
  ]},
  {id:"kou16l7",title:"간접 화법 연습",icon:"💬",xp:22,board:true,steps:[
        {type:"intro",title:"Putting It All Together",desc:"Practice all 4 types of reported speech\nin natural conversations.",goals:["Use all 4 indirect speech types fluently","Combine with honorifics","Report online and offline conversations","Distinguish command vs suggestion"]},
        {type:"teach",trg:"전달하다",src:"to deliver, to convey",pos:"verb",gender:null,phonetic:"jeon-dal-ha-da",note:"COMPOUND: 전(transmit/傳) + 달(reach/達).\nTransmit-reach = deliver/convey.\n메시지를 전달하다 = deliver a message.",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"teach",trg:"소식",src:"news, word (from someone)",pos:"noun",gender:null,phonetic:"so-sik",note:"COMPOUND: 소(small/消) + 식(information/息).\n좋은 소식 = good news.\n소식을 전하다 = pass on news.",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"mc",q:"뉴스에서 내일 비가 온다고 했어요.\n(The news said it will rain tomorrow.)\nType of reported speech:",opts:["Reported statement","Reported question","Reported command","Reported suggestion"],ans:"Reported statement",hint:"-(ㄴ)다고 = statement. News reported a fact."},
        {type:"fb",opts:["냐고","다고","라고","자고"],hint:"Sibling asked a question about direction. Question ending.",s:"동생이 어디 가{1} 물어봤어요.\n(My younger sibling asked where I am going.)",a:"냐고"},
        {type:"mc",q:"의사가 운동하라고 했어요.\n(The doctor told me to exercise.)\nType of reported speech:",opts:["Reported command","Reported statement","Reported question","Reported suggestion"],ans:"Reported command",hint:"-(으)라고 = command. The doctor gave an order."},
        {type:"fb",opts:["하자고","하라고","한다고","하냐고"],hint:"Friend proposed doing something together. Suggestion ending.",s:"친구가 같이 공부{1} 했어요.\n(My friend suggested studying together.)",a:"하자고"},
        {type:"drag_fill",hint:"A: What did the teacher say? (honorific past) B: command to be quiet.",s:"A: 선생님이 뭐라고 {1}?\nB: 조용히 하{2} 하셨어요.\n(A: What did the teacher say?\nB: They told us to be quiet.)",blanks:{"1":"하셨어요","2":"라고"},pool:["하셨어요","라고","했어요","다고","냐고"]},
        {type:"mc",q:"Convert direct to indirect:\n'같이 점심 먹자.' →",opts:["같이 점심 먹자고 했어요","같이 점심 먹는다고 했어요","같이 점심 먹냐고 했어요","같이 점심 먹으라고 했어요"],ans:"같이 점심 먹자고 했어요",hint:"먹자 = let's eat (suggestion base). Reported: 먹자고 했어요."},
        {type:"fb",opts:["냐고","다고","라고","자고"],hint:"Friend asked a question via messaging. Question ending.",s:"카톡에서 친구가 어디{1} 물어봤어요.\n(On KakaoTalk, my friend asked where I am.)",a:"냐고"},
        {type:"match",pairs:[{trg:"온다고 했어요",src:"said they are coming"},{trg:"오냐고 했어요",src:"asked if coming"},{trg:"오라고 했어요",src:"told to come"},{trg:"오자고 했어요",src:"suggested coming"}]},
        {type:"mc",q:"할머니가 잘 먹으라고 하셨어요.\nNotice TWO grammar layers:",opts:["Honorific -(으)시- on 하다 + reported command -(으)라고","Only honorific is used","Only reported speech is used","Neither is used"],ans:"Honorific -(으)시- on 하다 + reported command -(으)라고",hint:"먹으라고 = command. 하셨어요 = honorific past of 하다. Two layers combined."},
        {type:"drag_fill",hint:"News: verb statement (좋아지다 present). Citizens: noun+아니다 → 아니라고.",s:"뉴스에서 경제가 좋아{1} 했어요. 하지만 국민들은 아니{2} 해요.\n(The news said the economy is improving. But citizens say it is not.)",blanks:{"1":"진다고","2":"라고"},pool:["진다고","라고","냐고","자고","졌다고"]},
        {type:"fb",opts:["소식","댓글","검색","카톡"],hint:"Good word/tidings from someone. Personal news.",s:"친구가 좋은 {1}이 있다고 했어요. 뭔지 궁금해요.\n(My friend said there is good ___. I am curious what it is.)",a:"소식"},
        {type:"fb",opts:["공유","검색","구독","업로드"],hint:"Friend sent content for my benefit, then gave a command to watch.",s:"친구가 좋은 영상을 {1}해 줬어요. 꼭 보라고 했어요.\n(My friend shared a good video for me. They told me to watch it.)",a:"공유"},
        {type:"drag_fill",hint:"First: suggestion (let us gather). Second: statement (it is good).",s:"소식을 전달했어요. 모임에 {1} 했어요. 다들 좋{2} 했어요.\n(I delivered the news. I suggested meeting up. Everyone said it is good.)",blanks:{"1":"모이자고","2":"다고"},pool:["모이자고","다고","모이라고","냐고","모인다고"]},
        {type:"mc",q:"사장님이 회의에 참석하라고 말씀하셨는데,\n동료가 같이 가자고 했어요.\n(The CEO told us to attend the meeting,\nand a colleague suggested going together.)\nHow many constructs layered?",opts:["Command -(으)라고 + Suggestion -자고 + honorific -(으)시- + contrast -는데","Only command and statement","Only two suggestions","Command + question + -(으)면"],ans:"Command -(으)라고 + Suggestion -자고 + honorific -(으)시- + contrast -는데",hint:"참석하라고 = command. 말씀하셨는데 = honorific + contrast. 가자고 = suggestion. Three constructs."},
        {type:"mc",q:"할머니가 많이 드시라고 하셨는데\n동생이 배 안 고프냐고 물어봤어요.\n(Grandma told me to eat a lot,\nbut my sibling asked if I am not hungry.)\nIdentify ALL grammar layers:",opts:["Honorific -(으)시- + command -(으)라고 + contrast -는데 + question -냐고","Only command and question","Only honorific and statement","Command + suggestion + statement"],ans:"Honorific -(으)시- + command -(으)라고 + contrast -는데 + question -냐고",hint:"드시라고 = honorific command. 하셨는데 = honorific contrast. 고프냐고 = question. Four layers."},
        {type:"fb",opts:["라고","다고","냐고","자고"],hint:"-(으)라고 하다 = reported command. Parents commanded: come home early.",s:"부모님이 일찍 들어오{1} 하셨어요.\n(My parents told me to come home early.)",a:["라고"]},
        {type:"mc",q:"친구가 주말에 같이 등산하자고 해서 갔어요.\n(My friend suggested hiking together on the weekend so I went.)",opts:["-자고 하다 + -아/어서","-(으)라고 하다 + -아/어서","-냐고 하다 + -니까","-다고 하다 + -아/어서"],ans:"-자고 하다 + -아/어서",hint:"Reported suggestion + cause: friend suggested so I went."},
        {type:"drag_fill",hint:"-(으)라고 하다 (command) + -는데 (contrast): commanded but disobeyed.",s:"선생님이 숙제를 {1} 하셨는데 학생들이 안 {2}.\n(The teacher told students to do homework but students did not do it.)",blanks:{"1":"하라고","2":"했어요"},pool:["하라고","했어요","하자고","해요","하다고","하는데"]}
  ]},
  {id:"kou16l8",title:"온라인 대화",icon:"🌐",xp:20,board:true,steps:[
        {type:"intro",title:"Online Conversations",desc:"How indirect speech works\nin Korean digital communication.",goals:["Read Korean social media naturally","Understand reported speech in context","Combine internet slang with grammar","Navigate Korean online spaces"]},
        {type:"teach",trg:"리뷰",src:"review (online)",pos:"noun",gender:null,phonetic:"ri-byu",note:"Konglish from English 'review.'\n리뷰를 쓰다 = write a review.\n리뷰가 좋아요 = the reviews are good.",example:"A: 이 식당 리뷰 봤어요? B: 네, 리뷰가 아주 좋더라고요. A: 맛있다고 한 리뷰가 많아요? B: 네, 별점 다섯 개가 대부분이에요. A: 그러면 가 볼까요? B: 좋아요. 저도 리뷰 남기고 싶어요.",exampleSrc:"A: Did you see the reviews for this restaurant? B: Yes, the reviews were very good. A: Are there many reviews that said it is delicious? B: Yes, most of them are five stars. A: Then shall we try going? B: Sure. I want to leave a review too.",funFact:"A Konglish loanword adapted from English. Korean has borrowed many modern and tech words."},
        {type:"teach",trg:"조회수",src:"view count (online)",pos:"num",gender:null,phonetic:"jo-hoe-su",note:"COMPOUND: 조(look/照) + 회(times/回) + 수(number/數).\nLook-times-number = view count.\n조회수 100만 = 1 million views.",funFact:"Korean builds words by combining meaning blocks. Understanding the parts unlocks entire word families."},
        {type:"teach",trg:"알림",src:"notification, alert",pos:"intj",gender:null,phonetic:"al-lim",note:"From 알리다 (to notify).\n알림이 왔어요 = a notification came.\n알림을 켜다/끄다 = turn on/off notifications.",example:"A: 방금 카톡 알림이 왔어요. B: 누구한테서 왔어요? A: 회사에서요. 내일 회의가 있대요. B: 저도 알림을 확인해 볼게요. A: 알림을 꺼 놓으면 못 봐요. B: 맞아요. 그래서 항상 켜 놔요.",exampleSrc:"A: A KakaoTalk notification just came. B: Who was it from? A: From the company. They say there is a meeting tomorrow. B: I will check my notifications too. A: If you turn off notifications you will miss them. B: That is right. So I always keep them on.",funFact:"Korean has rich exclamations that express subtle emotions. Tone and context determine the exact feeling."},
        {type:"mc",q:"인스타에서 팔로워가 맛있대요.\n(A follower on Instagram says it is delicious.)\n맛있대요 means:",opts:["They say it is delicious","Is it delicious?","Make it delicious","It used to be delicious"],ans:"They say it is delicious",hint:"맛있대요 = 맛있다고 해요 (shortened statement)."},
        {type:"fb",opts:["래요","대요","냬요","재요"],hint:"별로 is followed by 라고. Noun-like + -(이)라고 해요 shortens to 래요.",s:"댓글에 별로{1}. 안 가는 게 좋을 것 같아요.\n(The comments say it is not great. I think it is better not to go.)",a:"래요"},
        {type:"mc",q:"친구가 카톡으로 '내일 뭐 해?' 보냈어요.\n(My friend sent 'What are you doing tomorrow?' via KakaoTalk.)\nIn reported speech:",opts:["내일 뭐 하냐고 했어요","내일 뭐 한다고 했어요","내일 뭐 하라고 했어요","내일 뭐 하자고 했어요"],ans:"내일 뭐 하냐고 했어요",hint:"'뭐 해?' is a question. Reported question ending."},
        {type:"fb",opts:["래요","대요","냬요","재요"],hint:"최고 is a noun. Noun + (이)라고 해요 shortens to 래요.",s:"블로그에 이 식당이 최고{1}. 가 볼까요?\n(The blog says this restaurant is the best. Shall we try going?)",a:"래요"},
        {type:"tip",title:"Korean Internet Platforms",text:"Korea's internet culture:\n\n- 네이버 (Naver): Korea's main search engine\n- 다음 (Daum): second search engine\n- 카카오톡: messaging monopoly\n- 네이버 카페: community forums\n- DC인사이드: Korean equivalent of Reddit\n- 에브리타임: university student app\n\nKorea has the world's fastest average\ninternet speed and highest smartphone\npenetration rate."},
        {type:"match",pairs:[{trg:"네이버",src:"Korea's main search engine"},{trg:"카카오톡",src:"messaging app"},{trg:"리뷰",src:"online review"},{trg:"조회수",src:"view count"}]},
        {type:"mc",q:"기사에서 한국이 인터넷 강국이라고 했어요.\n-(이)라고 is used because:",opts:["인터넷 강국 is a noun + 이다","인터넷 강국 is a verb","The sentence is a question","The sentence is a command"],ans:"인터넷 강국 is a noun + 이다",hint:"Noun + 이다 → -(이)라고. 강국이라고 = said it is a powerhouse."},
        {type:"fb",opts:["대요","래요","냬요","재요"],hint:"좋다 is an adjective. What's the shortened reported statement form for adjectives?",s:"리뷰에서 여기 서비스가 좋{1}.\n(Reviews say the service here is good.)",a:"대요"},
        {type:"fb",opts:["조회수","좋아요","댓글","알림"],hint:"The number that shows how many people watched.",s:"이 영상 {1}가 100만이래요!\n(They say this video's ___ is 1 million!)",a:"조회수"},
        {type:"drag_fill",hint:"A: Comments report a statement about atmosphere (adjective shortform). B: exclamation.",s:"A: 이 카페 어때? 댓글에 {1}.\nB: {2}! 가 보자.\n(A: How is this cafe? Comments say ___.\nB: ___! Let us try it.)",blanks:{"1":"분위기 좋대요","2":"대박"},pool:["분위기 좋대요","분위기 좋냬요","대박","노잼","좋래요"]},
        {type:"mc",q:"한국 인터넷에서 '실화?' means:",opts:["For real? (Is this a true story?)","Fiction","Silk flower","Serious problem"],ans:"For real? (Is this a true story?)",hint:"실화 = true story. As a question: 'Is this for real?'"},
        {type:"fb",opts:["알림","리뷰","조회수","소식"],hint:"The ping/buzz that tells you a new message arrived.",s:"카톡 {1}이 와서 확인했더니 친구가 만나자고 했어요.\n(A ___ came on KakaoTalk, so I checked and my friend suggested meeting.)",a:"알림"},
        {type:"mc",q:"블로그 리뷰에서 이 영화가 꿀잼이래요.\n그런데 댓글에는 노잼이라고도 해요.\n(Blog reviews say this movie is super fun.\nBut comments also say it is boring.)\nWhat form do 이래요 and 이라고 share?",opts:["Both use -(이)라고 (noun reporting). 이래요 is shortened.","Both use -다고 (adjective reporting)","Both use -냐고 (question reporting)","They use different patterns"],ans:"Both use -(이)라고 (noun reporting). 이래요 is shortened.",hint:"꿀잼 and 노잼 are noun predicates. Noun + 이라고 해요 → 이래요 (shortened)."},
        {type:"drag_fill",hint:"Reviews: adjective statement. Second: written responses under a post.",s:"리뷰에 맛있{1} 해서 검색했는데, {2}가 별로 없었어요.\n(Reviews said it is tasty so I searched, but there were not many ___.)",blanks:{"1":"다고","2":"댓글"},pool:["다고","댓글","냐고","좋아요","라고"]},
        {type:"fb",opts:["조회수","좋아요","구독","댓글"],hint:"The number showing how many people watched a video.",s:"유튜브 {1}가 1000만이래요. 대박이에요!\n(They say the YouTube ___ is 10 million. Amazing!)",a:"조회수"},
        {type:"mc",q:"친구가 카톡 알림을 보고 확인했대요.\n리뷰에 서비스가 좋다고 써 있었대요.\n(My friend said they checked after a KakaoTalk notification.\nThey said the review had written that the service is good.)\nHow many shortened reported statements (-대요)?",opts:["Two: 확인했대요 and 있었대요","One: only 확인했대요","One: only 있었대요","None"],ans:"Two: 확인했대요 and 있었대요",hint:"확인했대요 = 확인했다고 해요. 있었대요 = 있었다고 해요. Both shortened past statements."},
        {type:"mc",q:"온라인에서 한국어를 공부하는 사람이 많아지고 있어요.\n(The number of people studying Korean online is increasing.)",opts:["-아/어지다 + -고 있다","-게 되다 + -고 있다","-기로 하다 + -는 편이다","-아/어 보다 + -고 싶다"],ans:"-아/어지다 + -고 있다",hint:"많아지다 (become many) + progressive: an ongoing increase."},
        {type:"fb",opts:["다고","라고","냐고","자고"],hint:"-다고 하다 = reported statement. Friend said: it is good.",s:"한국 친구가 이 앱이 좋{1} 추천해 줬어요.\n(A Korean friend recommended this app saying it was good.)",a:["다고"]}
  ]},
  {id:"kou16l9",title:"복습 + 퀴즈",icon:"📝",xp:20,board:true,steps:[
        {type:"intro",title:"Unit 16 Review",desc:"Review all indirect speech and honorifics.\n\n-(ㄴ)다고, -냐고, -(으)라고, -자고.\n-(으)시- honorifics.\nInternet vocabulary.",goals:["Review all 4 indirect speech types","Test honorific usage","Apply internet vocabulary","Combine 3+ constructs fluently"]},
        {type:"mc",q:"친구가 내일 온다고 했어요.\n(My friend said they are coming tomorrow.)\nType of reported speech:",opts:["Statement","Question","Command","Suggestion"],ans:"Statement",hint:"-(ㄴ)다고 = statement. Friend stated a fact."},
        {type:"fb",opts:["라고","다고","냐고","자고"],hint:"Mom gave an instruction. Command ending for 오다 (vowel stem).",s:"엄마가 빨리 오{1} 했어요.\n(Mom told me to come quickly.)",a:"라고"},
        {type:"mc",q:"할머니가 뭐 드시고 싶으세요? combines:",opts:["Honorific 드시다 + -(으)시- on 싶다","Only 드시다 is honorific","Only -(으)시- appears","No honorifics in this sentence"],ans:"Honorific 드시다 + -(으)시- on 싶다",hint:"드시다 (honorific eat) + 싶으시다 (honorific want). Two levels of respect."},
        {type:"fb",opts:["세요","어요","시어요","셔요"],hint:"자다 honorific = 주무시다. Present polite ending.",s:"할아버지가 방에서 주무{1}.\n(Grandfather is sleeping in the room.)",a:"세요"},
        {type:"match",pairs:[{trg:"간다고",src:"says going (statement)"},{trg:"가냐고",src:"asks if going (question)"},{trg:"가라고",src:"tells to go (command)"},{trg:"가자고",src:"suggests going (suggestion)"}]},
        {type:"fb",opts:["댓글","검색","카톡","알림"],hint:"Written response below an online video.",s:"이 영상에 {1}을 달고 좋아요를 눌러 주세요.\n(Please leave a ___ and press like on this video.)",a:"댓글"},
        {type:"mc",q:"ㅋㅋㅋ, ㅠㅠ, 대박, 꿀잼 are all:",opts:["Korean internet slang","Formal Korean words","Grammar patterns","Honorific forms"],ans:"Korean internet slang",hint:"All common in online Korean communication, not textbook language."},
        {type:"drag_fill",hint:"News: verb statement. Someone honored: command to bring umbrella.",s:"뉴스에서 내일 비가 {1} 했어요. 우산을 가져가{2} 말씀하셨어요.\n(The news said it will rain. They told us to bring an umbrella.)",blanks:{"1":"온다고","2":"라고"},pool:["온다고","라고","오냐고","오자고","온대요"]},
        {type:"fb",opts:["하자고","하라고","한다고","하냐고"],hint:"Friend proposed something together. Suggestion ending.",s:"친구가 같이 공부{1} 했는데, 저는 피곤해서 못 간다고 했어요.\n(My friend suggested studying together, but I said I cannot go because I am tired.)",a:"하자고"},
        {type:"mc",q:"맛있대요 = 맛있다고 해요.\nThe shortened form contracts:",opts:["다고 해 → 대 (middle syllables merge)","Nothing, it is a different word","The subject is removed","The verb changes"],ans:"다고 해 → 대 (middle syllables merge)",hint:"-다고 해요 contracts to -대요. The 고 해 part merges into 대."},
        {type:"match",pairs:[{trg:"인터넷",src:"internet"},{trg:"댓글",src:"comment"},{trg:"검색하다",src:"to search"},{trg:"카톡",src:"KakaoTalk"}]},
        {type:"fb",opts:["리뷰","알림","조회수","소식"],hint:"Written evaluations of a place on a blog.",s:"블로그 {1}에서 이 카페가 좋대요.\n(Blog ___s say this cafe is good.)",a:"리뷰"},
        {type:"drag_fill",hint:"First: reported question (잘 지내다). Second: reported command (먹다, consonant stem).",s:"할아버지가 잘 {1}냐고 물어보셨어요. 그리고 밥 {2}라고 하셨어요.\n(Grandfather asked if I am doing well. And told me to eat.)",blanks:{"1":"지내","2":"먹으"},pool:["지내","먹으","지낸다고","먹자고","있으"]},
        {type:"drag_fill",hint:"Teacher: honorific command. Friend: suggestion. Two different speech types.",s:"선생님이 열심히 공부하{1} 하셨어요. 친구가 같이 하{2} 했어요.\n(The teacher told us to study hard. A friend suggested doing it together.)",blanks:{"1":"라고","2":"자고"},pool:["라고","자고","다고","냐고","이라고"]},
        {type:"mc",q:"댓글에 좋대요. 팔로워가 어디냬요.\n사장님이 오시라고 하셨어요. 같이 가자고 해요.\n(Comments say it is good. A follower asks where.\nThe owner told us to come. I suggest going together.)\nAll FOUR indirect speech types appear:",opts:["Statement -대요, Question -냬요, Command -(으)시라고, Suggestion -자고","Only three types appear","Only statement and question","Only command and suggestion"],ans:"Statement -대요, Question -냬요, Command -(으)시라고, Suggestion -자고",hint:"좋대요 = statement. 어디냬요 = question. 오시라고 = honorific command. 가자고 = suggestion."},
        {type:"drag_fill",hint:"Three indirect speech types: question, statement, suggestion. All with grandma honorific.",s:"할머니가 잘 {1} 물어보셨어요. 건강하시{2} 말씀하셨어요. 같이 밥 먹{3} 하셨어요.\n(Grandma asked if I am eating well. She said she is healthy. She suggested eating together.)",blanks:{"1":"먹냐고","2":"다고","3":"자고"},pool:["먹냐고","다고","자고","먹으라고","먹는다고","냐고"]},
        {type:"fb",opts:["검색","댓글","업로드","구독"],hint:"Looking up information on a search engine.",s:"네이버에서 {1}했는데 정보가 많아서 게시판에 공유했어요.\n(I ___ on Naver and there was a lot of information so I shared it on the forum.)",a:"검색"},
        {type:"mc",q:"엄마가 밥 먹었냐고 하셨어요.\n(Mom asked if I ate.)",opts:["-냐고 (question)","-다고 (statement)","-(으)라고 (command)","-자고 (suggestion)"],ans:"-냐고 (question)",hint:"-냐고 reports a question someone asked."},
        {type:"fb",opts:["먹으라고","먹다고","먹냐고","먹자고"],hint:"-(으)라고 하다 = reported command. Doctor commanded to take medicine.",s:"의사가 약을 꼭 {1} 하셨어요.\n(The doctor told me to make sure to take the medicine.)",a:["먹으라고"]},
        {type:"drag_fill",hint:"-자고 하다 (suggestion) + -아/어서 (so): suggested and then went.",s:"친구가 같이 {1} 해서 노래방에 {2}.\n(My friend suggested going together so we went to noraebang.)",blanks:{"1":"가자고","2":"갔어요"},pool:["가자고","갔어요","가라고","가요","가다고","갈 거예요"]},
        {type:"match",pairs:[{trg:"뭐 먹었냐고 했어요",src:"asked what I ate"},{trg:"빨리 오라고 했어요",src:"told me to come quickly"},{trg:"같이 가자고 했어요",src:"suggested going together"},{trg:"맛있다고 했어요",src:"said it was delicious"}]}
  ]}
]};
